/// Try to fold ceiling division pattern:
/// (X >> shift) + zext((X & mask) != 0) --> (X + mask) >> shift
/// where mask = (1 << shift) - 1
static Instruction *foldAddToCeilDiv(BinaryOperator &Add) {
  Value *X;
  const APInt *ShiftAmt;
  // Match: (X >> shift) + ...
  if (!match(Add.getOperand(0), m_LShr(m_Value(X), m_APInt(ShiftAmt))))
    return nullptr;

  unsigned BitWidth = Add.getType()->getScalarSizeInBits();
  unsigned Shift = ShiftAmt->getZExtValue();
  if (Shift == 0 || Shift >= BitWidth)
    return nullptr;

  // mask = (1 << shift) - 1
  APInt Mask = APInt::getLowBitsSet(BitWidth, Shift);

  Value *AndVal;
  const APInt *AndMask;
  CmpPredicate Pred;
  const APInt *CmpVal;
  // Match: zext((X & mask) != 0)
  // The icmp can be ne, eq with 0, ugt with -1, etc.
  // We match: zext(icmp pred (X & mask), cmp_val)
  if (!match(Add.getOperand(1),
             m_ZExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(AndMask)),
                           m_APInt(CmpVal)))))
    return nullptr;

  // Verify the mask matches: mask = (1 << shift) - 1
  if (*AndMask != Mask)
    return nullptr;

  // Verify the comparison is checking for non-zero: (X & mask) != 0
  // This can be: icmp ne (X & mask), 0 OR icmp ugt (X & mask), -1 (which is always false, not our case)
  // or: icmp eq (X & mask), 0 (and then we'd need to negate)
  // The pattern we want is (X & mask) != 0, which is icmp ne ..., 0
  if (Pred != ICmpInst::ICMP_NE || !CmpVal->isZero())
    return nullptr;

  // (X >> shift) + zext((X & mask) != 0) --> (X + mask) >> shift
  Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), Mask));
  return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Add.getType(), Shift));
}
