/// where mask = (1 << shift) - 1
static Instruction *foldAddToCeilDiv(BinaryOperator &Add, InstCombinerImpl &IC) {
  Value *Op0 = Add.getOperand(0);
  Value *Op1 = Add.getOperand(1);

  Value *X;
  const APInt *ShiftAmt;

  // Match: (X >> shift) + ... or ... + (X >> shift)
  Value *LshrOp;
  if (match(Op0, m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
    LshrOp = Op0;
  } else if (match(Op1, m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
    LshrOp = Op1;
  } else {
    return nullptr;
