  unsigned BitWidth = Add.getType()->getScalarSizeInBits();
  unsigned Shift = ShiftAmt->getZExtValue();
  if (Shift == 0 || Shift >= BitWidth)
    return nullptr;

  // mask = (1 << shift) - 1
  APInt Mask = APInt::getLowBitsSet(BitWidth, Shift);

  // Find the zext operand (the one that's not the lshr)
  Value *ZextOp = (LshrOp == Op0) ? Op1 : Op0;

  const APInt *AndMask;
  CmpPredicate Pred;
  const APInt *CmpVal;
